// ── JSON Output Utilities ───────────────────────────────────────────────────
// Shared formatting for --json flag across all CLI commands.

import { MtCliError } from '../client.js';

// ── Public API ──────────────────────────────────────────────────────────────

export interface JsonErrorShape {
  error: string;
  code: string;
  details?: unknown;
}

/**
 * Write a JSON payload to stdout (pretty-printed, trailing newline).
 */
export function outputJson(data: unknown): void {
  process.stdout.write(JSON.stringify(data, null, 2) + '\n');
}

/**
 * Format an error as structured JSON, write to stdout, and exit with code 1.
 * Never returns (return type is `never`).
 */
export function outputJsonError(err: unknown): never {
  const payload: JsonErrorShape = {
    error: getErrorMessage(err),
    code: formatErrorCode(err),
  };

  const details = formatErrorDetails(err);
  if (details !== undefined) {
    payload.details = details;
  }

  process.stdout.write(JSON.stringify(payload, null, 2) + '\n');
  process.exit(1);
}

// ── Error Code Mapping ──────────────────────────────────────────────────────

/**
 * Map an error to a machine-readable code string.
 *
 * - MtCliError with HTTP status → `HTTP_${status}` (e.g. `HTTP_404`)
 * - MtCliError with status 0 and abort message → `TIMEOUT`
 * - MtCliError with status 0 and fetch message → `NETWORK_ERROR`
 * - Anything else → `UNKNOWN_ERROR`
 */
export function formatErrorCode(err: unknown): string {
  if (err instanceof MtCliError) {
    if (err.status === 0) {
      // Timeout: abort-related message
      if (err.message.includes('请求超时') || err.message.includes('timeout')) {
        return 'TIMEOUT';
      }
      // Network: fetch-related message
      if (err.message.includes('无法连接') || err.message.includes('fetch')) {
        return 'NETWORK_ERROR';
      }
    }
    if (err.status > 0) {
      return `HTTP_${err.status}`;
    }
  }
  return 'UNKNOWN_ERROR';
}

/**
 * Extract structured details from MtCliError (url, suggestion),
 * or return undefined for unknown error types.
 */
export function formatErrorDetails(err: unknown): unknown {
  if (err instanceof MtCliError) {
    const details: Record<string, string> = {};
    if (err.url) details.url = err.url;
    if (err.suggestion) details.suggestion = err.suggestion;
    if (Object.keys(details).length > 0) return details;
  }
  return undefined;
}

// ── Internal Helpers ────────────────────────────────────────────────────────

function getErrorMessage(err: unknown): string {
  if (err instanceof Error) {
    return err.message;
  }
  if (typeof err === 'string') {
    return err;
  }
  return String(err);
}

import type { Command } from 'commander';
import type { ResolvedConfig } from '../config.js';
import { MtClient } from '../client.js';
import type { TaskResponse } from '../types.js';
import { statusLabel, taskRow } from '../utils/format.js';

export function registerListCommand(
  tasksGroup: Command,
  getConfig: () => ResolvedConfig,
): void {
  tasksGroup
    .command('list')
    .description('列出所有任务（默认排除已完成和已跳过）')
    .option('--status <status>', '按状态筛选 (todo|in-progress|blocked|review|done|skipped)')
    .action(async (opts: { status?: string }) => {
      const config = getConfig();
      const client = new MtClient({ baseUrl: config.serverUrl, apiKey: config.apiKey });

      try {
        const params = new URLSearchParams({ milestoneId: config.milestoneId });
        // Default filter excludes closed tasks (done, skipped)
        const status = opts.status;
        if (status) {
          params.set('status', status);
        }

        const tasks = await client.get<TaskResponse[]>(`/api/tasks?${params}`);

        if (tasks.length === 0) {
          console.log(`\n  暂无${status ? `状态为「${statusLabel(status)}」的` : ''}任务。\n`);
          return;
        }

        // Default: exclude done/skipped unless explicitly requested
        const filtered = status
          ? tasks
          : tasks.filter((t) => t.status !== 'done' && t.status !== 'skipped');

        if (filtered.length === 0) {
          console.log('\n  所有任务均已完成或跳过。使用 --status all 查看全部。\n');
          return;
        }

        console.log(`\n  共 ${filtered.length} 个任务:\n`);
        for (const task of filtered) {
          console.log(taskRow(task));
          console.log('');
        }
      } catch (err) {
        if (err instanceof Error) {
          console.error(err.message);
        }
        process.exit(1);
      }
    });
}

import type { Command } from 'commander';
import type { ResolvedConfig } from '../config.js';
import { MtClient } from '../client.js';
import type { TaskResponse } from '../types.js';
import { parseTaskId, resolveTaskId } from '../utils/id.js';
import { statusLabel, progressBar, formatDate, divider } from '../utils/format.js';

/**
 * Resolve #N references in a description string.
 * Replaces each #N with a summary line from the task list.
 */
function resolveDescriptionReferences(
  description: string,
  allTasks: TaskResponse[],
): string {
  return description.replace(/#(\d+)/g, (match, numStr) => {
    const shortId = parseInt(numStr, 10);
    const ref = allTasks.find((t) => t.shortId === shortId);
    if (!ref) {
      return `${match} (引用的任务不存在)`;
    }
    return `${match} [${ref.title}] (${statusLabel(ref.status)})`;
  });
}

export function registerShowCommand(
  tasksGroup: Command,
  getConfig: () => ResolvedConfig,
): void {
  tasksGroup
    .command('show <taskId>')
    .description('查看任务详情')
    .action(async (taskId: string) => {
      const config = getConfig();
      const client = new MtClient({ baseUrl: config.serverUrl, apiKey: config.apiKey });

      try {
        const parsed = parseTaskId(taskId);
        const fullId = await resolveTaskId(parsed, () =>
          client.get<TaskResponse[]>(`/api/tasks?milestoneId=${encodeURIComponent(config.milestoneId)}`),
        );

        // Fetch task detail
        const task = await client.get<TaskResponse>(`/api/tasks/${encodeURIComponent(fullId)}`);

        // Fetch all tasks for inline reference resolution
        const allTasks = await client.get<TaskResponse[]>(
          `/api/tasks?milestoneId=${encodeURIComponent(config.milestoneId)}`,
        );

        console.log('');
        console.log(divider('═', 40));
        console.log(`  #${task.shortId}  ${task.title}`);
        console.log(divider('═', 40));
        console.log('');
        console.log(`  ID:         ${task.id}`);
        console.log(`  模块:       ${task.moduleId}`);
        console.log(`  状态:       ${statusLabel(task.status)}`);
        console.log(`  负责人:     ${task.assignee || '(未分配)'}`);
        console.log('');

        if (task.subTotal > 0) {
          console.log(`  进度:       ${progressBar(task.subDone, task.subTotal)} (${task.subDone}/${task.subTotal})`);
          console.log('');
        }

        if (task.description) {
          const resolved = resolveDescriptionReferences(task.description, allTasks);
          console.log(divider('─', 40));
          console.log('  描述:');
          console.log('');
          // Indent description lines
          for (const line of resolved.split('\n')) {
            console.log(`    ${line}`);
          }
          console.log('');
        }

        if (task.references) {
          console.log(divider('─', 40));
          console.log(`  引用: ${task.references}`);
          console.log('');
        }

        if (task.progressMessage) {
          console.log(divider('─', 40));
          console.log('  进度说明:');
          console.log(`    ${task.progressMessage}`);
          console.log('');
        }

        if (task.commitHash) {
          console.log(`  Git 提交:   ${task.commitHash}`);
        }

        console.log('');
        console.log(divider('─', 40));
        console.log(`  创建时间:   ${formatDate(task.createdAt)}`);
        console.log(`  更新时间:   ${formatDate(task.updatedAt)}`);
        if (task.reportedAt) {
          console.log(`  报告时间:   ${formatDate(task.reportedAt)}`);
        }
        console.log(divider('═', 40));
        console.log('');
      } catch (err) {
        if (err instanceof Error) {
          console.error(err.message);
        }
        process.exit(1);
      }
    });
}

import type { Command } from 'commander';
import type { ResolvedConfig } from '../config.js';
import { MtClient } from '../client.js';
import type { TaskResponse } from '../types.js';
import { statusLabel, taskRow, progressBar } from '../utils/format.js';

export function registerMineCommand(
  tasksGroup: Command,
  getConfig: () => ResolvedConfig,
): void {
  tasksGroup
    .command('mine')
    .description('查看我领取的任务')
    .option('--agent <name>', 'Agent 名称（默认使用配置中的 agentName）')
    .action(async (opts: { agent?: string }) => {
      const config = getConfig();
      const client = new MtClient({ baseUrl: config.serverUrl, apiKey: config.apiKey });

      const agentName = opts.agent || config.agentName;
      if (!agentName) {
        console.error('[错误] 未指定 Agent 名称。请使用 --agent <name> 或在配置文件中设置 agentName。');
        process.exit(1);
      }

      try {
        const tasks = await client.get<TaskResponse[]>(
          `/api/tasks?milestoneId=${encodeURIComponent(config.milestoneId)}`,
        );

        const myTasks = tasks.filter((t) => t.assignee === agentName);

        if (myTasks.length === 0) {
          console.log(`\n  Agent「${agentName}」暂无已领取的任务。\n`);
          return;
        }

        // Sort: in-progress first, then by shortId
        const sorted = [...myTasks].sort((a, b) => {
          const order: Record<string, number> = { 'in-progress': 0, 'review': 1, 'blocked': 2, 'todo': 3, 'done': 4, 'skipped': 5 };
          const oa = order[a.status] ?? 9;
          const ob = order[b.status] ?? 9;
          if (oa !== ob) return oa - ob;
          return a.shortId - b.shortId;
        });

        console.log(`\n  Agent「${agentName}」共 ${sorted.length} 个任务:\n`);
        for (const task of sorted) {
          const id = `#${task.shortId}`.padEnd(6);
          const status = statusLabel(task.status).padEnd(8);
          const progress = task.subTotal > 0
            ? `  ${progressBar(task.subDone, task.subTotal)}`
            : '';
          console.log(`  ${id} ${status} ${task.title}${progress}`);
          console.log('');
        }
      } catch (err) {
        if (err instanceof Error) {
          console.error(err.message);
        }
        process.exit(1);
      }
    });
}

import type { Command } from 'commander';
import type { ResolvedConfig } from '../config.js';
import { MtClient } from '../client.js';
import type { TaskResponse } from '../types.js';
import { parseTaskId, resolveTaskId } from '../utils/id.js';

export function registerClaimCommand(
  tasksGroup: Command,
  getConfig: () => ResolvedConfig,
): void {
  tasksGroup
    .command('claim <taskId>')
    .description('领取一个任务')
    .option('--agent <name>', 'Agent 名称（默认使用配置中的 agentName）')
    .action(async (taskId: string, opts: { agent?: string }) => {
      const config = getConfig();
      const client = new MtClient({ baseUrl: config.serverUrl, apiKey: config.apiKey });

      const agentName = opts.agent || config.agentName;
      if (!agentName) {
        console.error('[错误] 未指定 Agent 名称。请使用 --agent <name> 或在配置文件中设置 agentName。');
        process.exit(1);
      }

      try {
        const parsed = parseTaskId(taskId);
        const fullId = await resolveTaskId(parsed, () =>
          client.get<TaskResponse[]>(`/api/tasks?milestoneId=${encodeURIComponent(config.milestoneId)}`),
        );

        const result = await client.post<TaskResponse>(`/api/tasks/${encodeURIComponent(fullId)}/claim`, {
          assignee: agentName,
        });

        console.log(`✓ 已领取 #${result.shortId}「${result.title}」`);
        console.log(`  负责人: ${result.assignee}`);
      } catch (err) {
        if (err instanceof Error) {
          const msg = err.message;
          // Check for 409 conflict
          if (msg.includes('409')) {
            console.error(`✗ 领取失败。任务 ${taskId} 已被其他 Agent 领取。`);
            console.error(`  请执行 'mt-cli tasks list --status todo' 查看可用任务。`);
          } else {
            console.error(msg);
          }
        }
        process.exit(1);
      }
    });
}

import type { Command } from 'commander';
import type { ResolvedConfig } from '../config.js';
import { MtClient } from '../client.js';
import type { TaskResponse } from '../types.js';
import { parseTaskId, resolveTaskId } from '../utils/id.js';
import { progressBar } from '../utils/format.js';

export function registerProgressCommand(
  tasksGroup: Command,
  getConfig: () => ResolvedConfig,
): void {
  tasksGroup
    .command('progress <taskId>')
    .description('更新任务进度')
    .option('--sub-total <n>', '子任务总数', parseInt)
    .option('--sub-done <n>', '已完成子任务数', parseInt)
    .option('--message <msg>', '进度说明')
    .action(async (taskId: string, opts: { subTotal?: number; subDone?: number; message?: string }) => {
      const config = getConfig();
      const client = new MtClient({ baseUrl: config.serverUrl, apiKey: config.apiKey });

      try {
        const parsed = parseTaskId(taskId);
        const fullId = await resolveTaskId(parsed, () =>
          client.get<TaskResponse[]>(`/api/tasks?milestoneId=${encodeURIComponent(config.milestoneId)}`),
        );

        const body: Record<string, unknown> = {};
        if (opts.message) body.progressMessage = opts.message;
        if (opts.subTotal !== undefined) body.subTotal = opts.subTotal;
        if (opts.subDone !== undefined) body.subDone = opts.subDone;

        const result = await client.post<TaskResponse>(`/api/tasks/${encodeURIComponent(fullId)}/progress`, body);

        console.log(`✓ 已更新 #${result.shortId}「${result.title}」的进度`);
        if (result.subTotal > 0) {
          console.log(`  ${progressBar(result.subDone, result.subTotal)} (${result.subDone}/${result.subTotal})`);
        }
        if (result.progressMessage) {
          console.log(`  说明: ${result.progressMessage}`);
        }
      } catch (err) {
        if (err instanceof Error) {
          console.error(err.message);
        }
        process.exit(1);
      }
    });
}

